#!/usr/bin/env python3
"""Generate lessons-279-391.json curriculum part."""

import json
from pathlib import Path

OUT = Path(__file__).resolve().parents[1] / "data" / "curriculum-parts" / "lessons-279-391.json"


def entry(lesson, book_id, chapter, verse, text, hist, narr, questions):
    return {
        "lesson": lesson,
        "book_id": book_id,
        "chapter": chapter,
        "verse_start": verse,
        "verse_end": verse,
        "text": text,
        "historical_context": hist,
        "preceding_narrative": narr,
        "discussion_questions": questions,
    }


# (lesson, book_id, chapter, verse, text, historical_context, preceding_narrative, [questions])
LESSONS = [
    entry(279, 1, 2, 7,
        "Then the Lord God formed a man from the dust of the ground and breathed into his nostrils the breath of life, and the man became a living being.",
        "<p>Genesis was composed in the ancient Near East, where creation accounts shaped how peoples understood identity, worship, and human dignity. Israel's story stands apart by presenting one sovereign God who personally forms humanity rather than leaving people as accidental byproducts of chaos.</p>",
        "<p>Genesis 1 describes God speaking the cosmos into order. Genesis 2 zooms in on Eden, where God plants a garden and places the man he formed to work and care for it. Before sin enters the world, this verse reveals that human life is a direct gift from God's own breath.</p>",
        ["What does it mean that God personally formed humanity?", "How does knowing life comes from God's breath affect how you treat others?", "Why is it significant that humans became living beings through divine breath rather than mere dust?"]),
    entry(280, 1, 3, 15,
        "And I will put enmity between you and the woman, and between your offspring and hers; he will crush your head, and you will strike his heel.",
        "<p>After Adam and Eve disobeyed in Eden, God addressed the serpent in the hearing of the first humans. Ancient readers would have recognized this as a judicial pronouncement within a covenant story, not a myth detached from history. The promise of a coming victor became a thread running through Israel's hope.</p>",
        "<p>The fall brought shame, blame, and curse upon creation. God first confronts the serpent, then announces consequences for the woman and the man. Embedded in judgment is the first gospel hint: hostility between the serpent's offspring and the woman's offspring, culminating in a decisive blow to evil.</p>",
        ["How does this verse point beyond Adam and Eve to future redemption?", "What does enmity with evil look like in a believer's daily life?", "Why would God announce hope immediately after humanity's first rebellion?"]),
    entry(281, 1, 4, 9,
        "Then the Lord said to Cain, \"Where is your brother Abel?\" \"I don't know,\" he replied. \"Am I my brother's keeper?\"",
        "<p>Cain and Abel lived in the earliest period of human society outside Eden, when worship, agriculture, and family loyalty were forming patterns for generations to come. God's question to Cain establishes that private violence cannot be hidden from the Lord and that brotherly responsibility is not optional.</p>",
        "<p>Both brothers brought offerings, but God regarded Abel's and not Cain's. Cain's anger grew dangerous, and God warned him that sin was crouching at the door. Cain ignored the warning, murdered Abel in the field, and then tried to evade accountability when God confronted him.</p>",
        ["How does Cain's question still echo in modern excuses for neglecting others?", "What responsibilities do you have toward people God has placed near you?", "Why does God ask a question he already knows the answer to?"]),
    entry(282, 1, 6, 8,
        "But Noah found favor in the eyes of the Lord.",
        "<p>By Noah's day, human wickedness had filled the earth. In a world where violence and corruption were widespread, one man's faithfulness mattered. Ancient flood narratives were common in the region, but Genesis presents judgment and grace through the covenant God of Israel.</p>",
        "<p>Genesis 6 describes a culture given over to evil, prompting God to grieve creation and resolve to act. Amid universal corruption, the narrative pauses to introduce Noah, a righteous man who walked faithfully with God and would become the means of preserving life.</p>",
        ["What does it mean to find favor with God in a corrupt culture?", "How can one person's faithfulness affect an entire household?", "Why does God sometimes preserve a remnant when judgment is near?"]),
    entry(283, 1, 9, 16,
        "Whenever the rainbow appears in the clouds, I will see it and remember the everlasting covenant between God and all living creatures of every kind on the earth.",
        "<p>After the flood, God established a covenant with Noah and all creation. In the ancient world, rainbows were natural phenomena, but here they become a public sign of divine promise. The covenant extended beyond Israel to every living creature on earth.</p>",
        "<p>Noah's family left the ark, offered sacrifice, and received God's blessing to fill the earth again. God set his bow in the clouds as a sign that he would never again destroy all life with a flood, sealing an enduring promise with creation itself.</p>",
        ["How do visible signs help people remember God's promises?", "What does this covenant teach about God's care for all creation?", "When have you seen a reminder of God's faithfulness in ordinary life?"]),
    entry(284, 1, 17, 1,
        "When Abram was ninety-nine years old, the Lord appeared to him and said, \"I am God Almighty; walk before me faithfully and be blameless.",
        "<p>Abram lived as a nomadic patriarch in Canaan, decades after leaving Ur. At ninety-nine, human hope of offspring seemed impossible. God appeared again to renew covenant promises using the name God Almighty, calling Abram into wholehearted obedience.</p>",
        "<p>Years earlier God called Abram and promised land and descendants. Ishmael had been born through Hagar, yet the promised child was still unborn. In chapter 17 God renames Abram to Abraham and announces that Sarah will bear Isaac, demanding faithful walking before him.</p>",
        ["What does walking faithfully before God look like when promises delay?", "Why might God call Abraham to blamelessness at such an old age?", "How does God's name God Almighty reshape our view of impossible situations?"]),
    entry(285, 1, 22, 14,
        "So Abraham called that place The Lord Will Provide. And to this day it is said, \"On the mountain of the Lord it will be provided.\"",
        "<p>Abraham's test on Mount Moriah took place in the hill country of what later became Jerusalem, a region central to Israel's worship. Child sacrifice was practiced by some neighboring peoples, but God stopped Abraham and provided a ram instead, foreshadowing substitutionary provision.</p>",
        "<p>God commanded Abraham to offer Isaac, the son of promise. Abraham obeyed, trusting God could raise the dead. At the last moment the angel stopped him, and Abraham saw a ram caught in a thicket. He named the place The Lord Will Provide in worshipful recognition.</p>",
        ["How does Abraham's trust on the mountain challenge your own obedience?", "What does God's provision of a substitute teach about grace?", "Where in your life have you seen the Lord provide at the moment of greatest need?"]),
    entry(286, 1, 24, 27,
        "saying, \"Praise be to the Lord, the God of my master Abraham, who has not abandoned his kindness and faithfulness to my master. As for me, the Lord has led me on the journey to the house of my master's relatives.\"",
        "<p>Abraham's servant traveled from Canaan to Mesopotamia to find a wife for Isaac, reflecting arranged marriage customs and clan loyalty in the patriarchal era. The servant's prayerful mission shows how God's covenant kindness extended through ordinary travel and hospitality.</p>",
        "<p>Abraham sent his chief servant with a solemn oath to seek a bride from his relatives, not from Canaanite peoples. The servant prayed for guidance at a well, and Rebekah's generous response confirmed God's leading. He worshiped immediately, praising God's faithful kindness.</p>",
        ["How does the servant's prayer model seeking God's guidance in practical decisions?", "What role does gratitude play when God answers clearly?", "How can kindness and faithfulness to prior generations shape your choices today?"]),
    entry(287, 1, 32, 28,
        "Then the man said, \"Your name will no longer be Jacob, but Israel, because you have struggled with God and with humans and have overcome.\"",
        "<p>Jacob was returning to Canaan after years with Laban, anxious about meeting Esau whose blessing he had taken. At the Jabbok River he wrestled through the night with a divine figure. Name changes in the ancient world marked transformed identity and new calling.</p>",
        "<p>Jacob sent gifts ahead to Esau and moved his family across the river. Alone, he wrestled until daybreak, refusing to let go without a blessing. The encounter left him limping but renamed Israel, a patriarch whose struggle became the nation's identity.</p>",
        ["What does it mean to wrestle with God honestly in prayer?", "How can struggle produce blessing rather than defeat?", "Why might God rename someone after a night of perseverance?"]),
    entry(288, 1, 39, 2,
        "The Lord was with Joseph so that he prospered, and he lived in the house of his Egyptian master.",
        "<p>Joseph was sold into slavery in Egypt during a period when Semitic peoples sometimes rose in foreign households. Though far from home and betrayed by brothers, God's presence with Joseph shows that covenant faithfulness is not limited by geography or status.</p>",
        "<p>Joseph's brothers hated him, threw him into a pit, and sold him to Ishmaelite traders. In Egypt, Potiphar bought him. Instead of disappearing into anonymous slavery, Joseph prospered because the Lord was with him and gave success in everything he did.</p>",
        ["How can God's presence change outcomes in unjust circumstances?", "What qualities might have helped Joseph prosper in Potiphar's house?", "Where do you need to trust that the Lord is with you though the situation feels unfair?"]),
    entry(289, 1, 45, 5,
        "And now, do not be distressed and do not be angry with yourselves for selling me here, because it was to save lives that God sent me ahead of you.",
        "<p>After years of famine, Joseph ruled Egypt as Pharaoh's governor. His brothers arrived seeking grain, not recognizing the brother they had sold. In a culture of family honor and guilt, Joseph's revelation reframed their evil act within God's larger purpose to preserve life.</p>",
        "<p>Joseph tested his brothers through hidden money, a silver cup, and the demand for Benjamin. Judah's plea showed changed hearts. Joseph could no longer restrain himself, wept openly, and disclosed his identity, urging them not to blame themselves because God had sent him ahead.</p>",
        ["How does Joseph's forgiveness differ from pretending harm never happened?", "When have you seen God redeem painful events for a greater good?", "What makes it hard to release others from guilt when God has already worked good through pain?"]),
    entry(290, 2, 12, 13,
        "The blood will be a sign for you on the houses where you are, and when I see the blood, I will pass over you. No destructive plague will touch you when I strike Egypt.",
        "<p>Israel was enslaved in Egypt when God announced the final plague against Pharaoh. Passover instructions were given on the eve of liberation, establishing a ritual Israel would observe for generations. Blood on doorframes marked homes under God's protection.</p>",
        "<p>After nine plagues hardened Pharaoh's heart, God commanded each household to take an unblemished lamb, slaughter it at twilight, and apply its blood to doorframes. They were to eat in haste, ready to leave. The blood became the sign that death would pass over them.</p>",
        ["Why was blood necessary as a sign of protection?", "How does Passover point to themes of deliverance and sacrifice?", "What does it mean for God's people to be marked as distinct in a crisis?"]),
    entry(291, 2, 15, 2,
        "\"The Lord is my strength and my defense; he has become my salvation. He is my God, and I will praise him, my father's God, and I will exalt him.",
        "<p>The Song of the Sea celebrates Israel's deliverance at the Red Sea, one of the earliest poetic responses to redemption in Scripture. Moses and Miriam led worship after Pharaoh's army was destroyed, declaring that the God of the fathers had become present salvation.</p>",
        "<p>Israel crossed the sea on dry ground while Egyptian chariots were swallowed by the waters. On the far shore, Moses and the people sang of God's mighty hand, thrown horse and rider into the sea, and exalted the Lord as warrior and savior.</p>",
        ["What events in your life could become reasons to exalt God publicly?", "How does calling God your strength change the way you face fear?", "Why is it important to link present salvation with the faith of previous generations?"]),
    entry(292, 2, 16, 20,
        "However, some of them paid no attention to Moses; they kept part of it until morning, but it was full of maggots and began to smell. So Moses was angry with them.",
        "<p>In the wilderness after the exodus, God provided manna daily to teach Israel dependence. Gathering more than a day's portion violated explicit instructions given in a context where trust, not hoarding, defined covenant life with the Lord who led them.</p>",
        "<p>Israel grumbled for food, and God sent manna with clear rules: gather enough for each day, and do not keep leftovers overnight except before the Sabbath. Some ignored Moses, kept extra manna, and found it spoiled by morning, provoking his anger.</p>",
        ["Where are you tempted to hoard instead of trusting daily provision?", "What does disobedience to clear instruction reveal about the heart?", "How does God use daily rhythms to train his people in faith?"]),
    entry(293, 2, 19, 5,
        "Now if you obey me fully and keep my covenant, then out of all nations you will be my treasured possession. Although the whole earth is mine,",
        "<p>At Mount Sinai, Israel met God as a nation recently freed from Egypt. Covenant language echoed ancient treaties, but here the great King chose a people for himself. Obedience was not earning salvation from slavery; it was the response of a redeemed community.</p>",
        "<p>Israel camped before the mountain while thunder, smoke, and trumpet sound signaled God's presence. Moses relayed God's offer: if they obeyed and kept covenant, they would be God's treasured possession, a kingdom of priests and a holy nation among all peoples.</p>",
        ["What does it mean to be God's treasured possession in everyday life?", "How is covenant obedience different from trying to earn God's love?", "Why did God choose one nation when the whole earth belongs to him?"]),
    entry(294, 2, 25, 8,
        "\"Then have them make a sanctuary for me, and I will dwell among them.",
        "<p>While Israel wandered toward Canaan, God gave Moses detailed instructions for a portable sanctuary. In the ancient world, temples signaled a deity's presence; Israel's tabernacle declared that the Lord who redeemed them would travel and dwell in their midst.</p>",
        "<p>After the golden calf incident and renewed covenant, God commanded contributions from willing hearts for a sacred dwelling. Skilled craftsmen would build the tabernacle according to heavenly pattern so that God could live among the people he had brought out of Egypt.</p>",
        ["Why would a holy God want to dwell among a flawed people?", "What does it mean for worship to be central to community life?", "How does God's desire for presence foreshadow later biblical themes?"]),
    entry(295, 2, 29, 45,
        "Then I will dwell among the Israelites and be their God.",
        "<p>The ordination of priests and consecration of the tabernacle completed the system through which Israel would approach God. Sacrifices, incense, and ritual holiness were not ends in themselves but the means by which God's dwelling among his people became real.</p>",
        "<p>Exodus 29 details how Aaron and his sons were to be ordained with offerings, garments, and seven days of consecration. The chapter closes with God's promise that once the tabernacle was established, he would dwell among Israel and be their God in covenant relationship.</p>",
        ["How does God's promise to dwell among Israel shape our view of worship?", "What does it mean for God to be your God in practical terms?", "Why is holiness essential when God draws near to a community?"]),
    entry(296, 3, 11, 45,
        "I am the Lord, who brought you up out of Egypt to be your God; therefore be holy, because I am holy.",
        "<p>Leviticus was given at Sinai to teach Israel how to live as God's holy people. Dietary and purity laws distinguished Israel from surrounding nations while reminding them that redemption from Egypt carried moral and ritual responsibility rooted in God's own character.</p>",
        "<p>Chapter 11 lists clean and unclean animals, instructing Israel to avoid what defiles. The chapter closes with a theological summary: the God who delivered them from slavery calls them to holiness that reflects his own nature, not mere cultural preference.</p>",
        ["How does remembering the exodus motivate holy living?", "What does holiness look like beyond ritual rules today?", "Why does God ground ethics in his own character rather than human opinion?"]),
    entry(297, 3, 17, 11,
        "For the life of a creature is in the blood, and I have given it to you to make atonement for yourselves on the altar; it is the blood that makes atonement for one's life.",
        "<p>Israel's sacrificial system operated within a worldview that treated blood as sacred because it represented life given by God. In a land surrounded by pagan worship, these laws guarded against misuse of blood while pointing to atonement for sin before a holy God.</p>",
        "<p>Leviticus 17 forbids eating blood and requires that sacrificial animals be brought to the tabernacle. God explains that blood, representing life, is appointed for atonement on the altar, making clear that forgiveness is costly and belongs to the Lord alone.</p>",
        ["Why is life-and-blood imagery so central to atonement?", "How does this verse help us understand later sacrificial themes in Scripture?", "What does it mean that forgiveness requires something given on our behalf?"]),
    entry(298, 4, 21, 4,
        "They traveled from Mount Hor along the route to the Red Sea, to go around Edom. But the people grew impatient on the way",
        "<p>Israel's wilderness generation was nearing the end of forty years of wandering. Edom refused passage through its territory, forcing a lengthy detour. Impatience on the road revealed a deeper spiritual problem: dissatisfaction with God's leading when the path was hard.</p>",
        "<p>Aaron died at Mount Hor, and Israel mourned thirty days. Rather than trusting God on the redirected route around Edom, the people became impatient and spoke against God and Moses, setting the stage for further judgment and bronze serpent provision.</p>",
        ["What situations make you impatient with God's timing or direction?", "How does complaining against leaders often reveal distrust of God?", "What helps you persevere when the journey takes longer than expected?"]),
    entry(299, 4, 22, 6,
        "\"Now come and put a curse on these people, because they are too powerful for me. Perhaps then I will be able to defeat them and drive them out of the land. For I know that whoever you bless is blessed, and whoever you curse is cursed.\"",
        "<p>Balak, king of Moab, feared Israel camped on his border after victories over Amorite kings. He summoned Balaam, a prophet known for effective blessings and curses, reflecting how ancient Near Eastern rulers sought spiritual power to secure military advantage.</p>",
        "<p>Israel's march toward Canaan alarmed Moab. Balak sent elders with fees for divination, asking Balaam to curse Israel so Moab could defeat them. Balaam acknowledged that prophetic speech ultimately depended on the God whose blessings could not be bought.</p>",
        ["Why do people seek spiritual power for personal advantage?", "How does Balak's fear mirror opposition to God's people today?", "What does Balaam's later story teach about the limits of human schemes against God's blessing?"]),
    entry(300, 5, 4, 29,
        "But if from there you seek the Lord your God, you will find him if you seek him with all your heart and with all your soul.",
        "<p>Moses addressed Israel on the plains of Moab before they entered Canaan, recounting their history and calling them to covenant faithfulness. Even exile and scattering were imaginable futures, yet Moses promised that wholehearted seeking would still lead to finding God.</p>",
        "<p>Deuteronomy 4 warns against idolatry after Israel sees God's greatness at Sinai. Moses anticipates disaster if they turn to other gods, yet even if they are driven to the ends of the earth, returning to seek the Lord with all their heart and soul will bring discovery.</p>",
        ["What does seeking God with all your heart look like practically?", "How does this verse offer hope after failure or exile?", "Why is halfhearted searching insufficient for finding the Lord?"]),
    entry(301, 5, 5, 16,
        "\"Honor your father and your mother, as the Lord your God has commanded you, so that you may live long and that it may go well with you in the land the Lord your God is giving you.",
        "<p>The Ten Commandments formed the moral core of Israel's covenant at Sinai. In a society where family structure sustained identity, land, and worship, honoring parents was both personal virtue and social foundation for flourishing in the promised land.</p>",
        "<p>Moses restated the Decalogue for the new generation about to cross the Jordan. After commands about exclusive loyalty to God and reverence for his name and Sabbath, he repeated the charge to honor father and mother with promise of long life and well-being.</p>",
        ["How does honoring parents differ from agreeing with everything they do?", "What does this command teach about God's design for family?", "How can adult children honor parents in ways that fit their season of life?"]),
    entry(302, 5, 10, 12,
        "And now, Israel, what does the Lord your God ask of you but to fear the Lord your God, to walk in obedience to him, to love him, to serve the Lord your God with all your heart and with all your soul,",
        "<p>Moses summarized covenant duty for Israel before entrance into Canaan. After decades in the wilderness, the people needed clarity that God required neither impossible mystery nor distant ritual, but reverent love expressed in wholehearted obedience and service.</p>",
        "<p>Deuteronomy 10 recounts covenant renewal and care for the vulnerable. Moses reminded Israel that heaven belongs to God, yet he chose their ancestors and circumcised hearts were his desire. The question what does God ask frames a life of fear, walk, love, and service.</p>",
        ["How do fear, obedience, love, and service fit together rather than conflict?", "What does serving God with all your soul require this week?", "Why does Moses frame covenant life as a simple question with a demanding answer?"]),
    entry(303, 5, 13, 3,
        "you must not listen to the words of that prophet or dreamer. The Lord your God is testing you to find out whether you love him with all your heart and with all your soul.",
        "<p>Israel would encounter prophets and dreamers in Canaan who could perform signs. Moses warned that authentic covenant loyalty could not be measured by spectacle alone. God permitted tests to reveal whether love for him was wholehearted or easily diverted.</p>",
        "<p>Deuteronomy 13 addresses the seduction of false prophets who entice Israel toward other gods, even with miraculous signs. Moses commanded rejection of such voices, explaining that God was testing whether his people loved him with undivided heart and soul.</p>",
        ["How can impressive experiences mislead people away from God?", "What tests have revealed the depth of your love for God?", "Why must love for God be measured by loyalty rather than curiosity?"]),
    entry(304, 5, 18, 13,
        "You must be blameless before the Lord your God.",
        "<p>Deuteronomy 18 regulates prophets, priests, and forbidden occult practices. Israel was not to seek guidance like the nations through divination. Instead, God would raise a prophet like Moses, and his people were called to integrity before the Lord alone.</p>",
        "<p>After forbidding child sacrifice, sorcery, and spiritists, Moses contrasted pagan inquiry with the prophet God would provide. The chapter's ethical climax is simple and sweeping: Israel must be blameless before the Lord their God, depending on his word not forbidden arts.</p>",
        ["What does blamelessness mean for people who still sin?", "How do modern substitutes for God's word resemble ancient divination?", "Why is integrity before God more important than insider spiritual knowledge?"]),
    entry(305, 5, 28, 9,
        "The Lord will establish you as his holy people, as he promised you on oath, if you keep the commands of the Lord your God and walk in obedience to him.",
        "<p>Deuteronomy 28 presents blessings and curses tied to covenant obedience as Israel prepared to possess Canaan. National identity as God's holy people was not automatic; it rested on sworn promise and responsive walking in the commands given at Sinai.</p>",
        "<p>Moses described prosperity, victory, and exaltation among nations if Israel listened to God. Before listing curses for disobedience, he promised that faithful obedience would establish them as the holy people God swore to make them, set apart among the nations.</p>",
        ["How is holiness both gift and responsibility for God's people?", "What does walking in obedience look like in community life?", "Why are blessings tied to covenant faithfulness in Deuteronomy?"]),
    entry(306, 5, 30, 19,
        "This day I call the heavens and the earth as witnesses against you that I have set before you life and death, blessings and curses. Now choose life, so that you and your children may live",
        "<p>Moses' final sermons on the plains of Moab framed Israel's future as a genuine decision before witnesses of creation itself. Covenant renewal was not abstract theology but an urgent call to choose life for themselves and coming generations.</p>",
        "<p>Deuteronomy 30 promised that God's command was not too difficult, for repentance and return were possible even after exile. Moses set life and death, blessing and curse before the people, calling heaven and earth as witnesses and urging them to choose life.</p>",
        ["What does choosing life mean beyond avoiding obvious sin?", "How do your choices affect the spiritual future of children or disciples?", "Why does Moses involve all creation as witness to Israel's decision?"]),
    entry(307, 5, 32, 39,
        "\"See now that I myself am he! There is no god besides me. I put to death and I bring to life, I have wounded and I will heal, and no one can deliver out of my hand.",
        "<p>The Song of Moses in Deuteronomy 32 reviewed Israel's history and God's justice. Near the end of Moses' life, this poetic testimony warned against apostasy while declaring God's unmatched sovereignty over life, death, wound, and healing.</p>",
        "<p>Moses taught Israel a song to remember God's faithfulness and their tendency to wander. In a dramatic divine speech within the song, the Lord declares that he alone is God, exercising absolute authority over life and death, and no rival can rescue from his hand.</p>",
        ["How does God's sovereignty over life and death bring comfort and awe?", "Why must Israel hear there is no god besides the Lord?", "When have you seen God heal what he allowed to wound?"]),
    entry(308, 6, 21, 25,
        "From the tribe of Gad, Ramoth in Gilead (a city of refuge for one accused of murder), Mahanaim,",
        "<p>Joshua 21 records towns given to the Levites, including cities of refuge where someone who killed unintentionally could flee for fair trial. This administrative list reflects God's concern for justice, worship, and ordered community life in the land Israel was settling.</p>",
        "<p>After dividing the land among tribes, Israel assigned cities to Levi, who received no territorial inheritance. Among Gad's contributions were Ramoth in Gilead, designated as a city of refuge, and Mahanaim, showing how law, mercy, and priestly service were woven into Israel's geography.</p>",
        ["Why would God embed mercy and refuge into the layout of the nation?", "How does this list remind us that worship and justice belong together?", "What modern equivalents protect the vulnerable while upholding truth?"]),
    entry(309, 7, 13, 22,
        "\"We are doomed to die!\" he said to his wife. \"We have seen God!\"",
        "<p>Manoah and his wife lived during the period of the judges, when Israel repeatedly turned from God and faced oppression. The angelic announcement of Samson's birth came in a culture marked by Philistine pressure and spiritual instability.</p>",
        "<p>An angel appeared to the barren wife of Manoah, promising a son set apart as a Nazirite. When Manoah offered a sacrifice, the angel ascended in the flame. Overwhelmed by the holiness of the encounter, Manoah feared they would die because they had seen God.</p>",
        ["Why do holy encounters sometimes produce fear before comfort?", "How does Manoah's reaction differ from his wife's calmer faith?", "What does this story teach about God's purposes beyond our terror?"]),
    entry(310, 8, 2, 12,
        "May the Lord repay you for what you have done. May you be richly rewarded by the Lord, the God of Israel, under whose wings you have come to take refuge.\"",
        "<p>Ruth is set in the period of the judges during a famine that drove Elimelek's family to Moab. After tragedy and return to Bethlehem, Ruth the Moabite gleaned in Boaz's field, illustrating covenant kindness within a society governed by harvest laws and clan responsibility.</p>",
        "<p>Boaz noticed Ruth's loyal care for Naomi and instructed workers to leave extra grain. He praised her for leaving homeland and gods to seek refuge under the wings of Israel's God. His blessing asked the Lord to repay and reward her faithful kindness.</p>",
        ["What does taking refuge under God's wings mean for outsiders today?", "How does Boaz model godly generosity within lawful boundaries?", "Who has shown you kindness that deserves grateful blessing?"]),
    entry(311, 9, 12, 24,
        "But be sure to fear the Lord and serve him faithfully with all your heart; consider what great things he has done for you.",
        "<p>Samuel led Israel as judge and prophet during the transition toward monarchy. At Gilgal he called the nation to renew loyalty to God after Saul's kingship was established, reminding them that political change must not replace wholehearted service to the Lord.</p>",
        "<p>Samuel defended his integrity before Israel, recounting years of righteous leadership. Though they had asked for a king, he urged them not to turn aside after worthless idols. True security lay in fearing the Lord, serving faithfully, and remembering God's great deeds.</p>",
        ["What great things has God done that you need to remember this week?", "How can political hopes distract from faithful service to God?", "What does fearing the Lord look like alongside gratitude?"]),
    entry(312, 9, 15, 22,
        "But Samuel replied: \"Does the Lord delight in burnt offerings and sacrifices as much as in obeying the Lord? To obey is better than sacrifice, and to heed is better than the fat of rams.",
        "<p>Saul was Israel's first king, anointed to lead against Philistine threats. When he failed to carry out God's command against Amalek fully, he returned offering sacrifices, assuming ritual could substitute for obedience in a crisis of leadership and trust.</p>",
        "<p>God rejected Saul for sparing Agag and the best livestock. Saul claimed the animals were for sacrifice at Gilgal. Samuel confronted him with one of Scripture's clearest statements that God values obedient hearts above religious performance without submission.</p>",
        ["Where are you tempted to substitute activity for obedience?", "Why is partial obedience especially dangerous for leaders?", "How does this verse reshape your view of worship and service?"]),
    entry(313, 10, 5, 4,
        "David was thirty years old when he became king, and he reigned forty years.",
        "<p>David's rise followed years of service to Saul, exile, and civil conflict. His reign united Judah and Israel and became the benchmark for future kings. This simple chronology anchors David's story in real history and long-term leadership responsibility.</p>",
        "<p>After Saul's death, David was anointed king over Judah in Hebron, then over all Israel. He captured Jerusalem and established his throne. The narrative pauses to note that David became king at thirty and ruled forty years, seven in Hebron and thirty-three in Jerusalem.</p>",
        ["Why does Scripture record ordinary biographical details about leaders?", "What can long obedience teach compared with brief success?", "How does David's timeline encourage patience in God's calling?"]),
    entry(314, 10, 23, 2,
        "\"The Spirit of the Lord spoke through me; his word was on my tongue.",
        "<p>These are among David's last words, presented as an oracle from the man God raised up as Israel's ideal king. In ancient Israel, Spirit-inspired speech through the king-prophet linked righteous rule with divine authority rather than mere political ambition.</p>",
        "<p>2 Samuel 23 records David's final poetic testimony and his mighty warriors. He opens by declaring that the Spirit of the Lord spoke through him and placed God's word on his tongue, framing his life and rule as divinely commissioned proclamation.</p>",
        ["What does it mean for God's word to be on a leader's tongue?", "How can you discern whether speech reflects the Spirit's leading?", "Why did David emphasize inspiration at the end of his life?"]),
    entry(315, 11, 4, 6,
        "Ahishar—palace administrator; Adoniram son of Abda—in charge of forced labor.",
        "<p>Solomon's administration reflected the organization of a growing monarchy with international trade, building projects, and centralized governance. Official lists in Kings show how Israel's united kingdom managed labor and palace affairs under David's successor.</p>",
        "<p>First Kings 4 names Solomon's officials and twelve district governors who supplied the royal household. Among palace administrators were Ahishar and Adoniram, who oversaw forced labor, revealing the structure behind Solomon's famed wisdom and extensive construction.</p>",
        ["What does responsible governance require beyond personal wisdom?", "How should power over labor be exercised justly?", "Why might Scripture preserve mundane administrative details?"]),
    entry(316, 11, 17, 14,
        "For this is what the Lord, the God of Israel, says: 'The jar of flour will not be used up and the jug of oil will not run dry until the day the Lord sends rain on the land.'\"",
        "<p>During a severe drought proclaimed by Elijah, a widow in Zarephath of Sidon faced starvation. God's provision through Elijah reached beyond Israel's borders, showing that the Lord who withholds rain also sustains those who trust him in famine.</p>",
        "<p>Elijah was sent to a Gentile widow gathering sticks for a final meal. Though she had only a handful of flour and a little oil, Elijah promised God's supply until rain returned. She obeyed, and the jar and jug miraculously did not run out.</p>",
        ["How does God sometimes provide through unlikely people and places?", "What role does obedience play when a promise seems impossible?", "Where do you need to trust daily provision rather than stored abundance?"]),
    entry(317, 11, 19, 12,
        "After the earthquake came a fire, but the Lord was not in the fire. And after the fire came a gentle whisper.",
        "<p>Elijah fled to Horeb after Jezebel threatened his life, discouraged despite victory on Mount Carmel. God met him not in wind, earthquake, or fire, but in a gentle whisper, reorienting prophetic ministry away from spectacle toward attentive listening.</p>",
        "<p>At the mountain of God, Elijah sheltered in a cave while the Lord passed by. Powerful phenomena preceded God's presence, yet the Lord was not in them. After the fire, a low whisper drew Elijah out to receive renewed commission and perspective.</p>",
        ["Why might God speak quietly after dramatic displays of power?", "When have you missed God's voice because you expected spectacle?", "How does a gentle whisper invite deeper attentiveness?"]),
    entry(318, 12, 2, 11,
        "As they were walking along and talking together, suddenly a chariot of fire and horses of fire appeared and separated the two of them, and Elijah went up to heaven in a whirlwind.",
        "<p>Elijah and Elisha ministered during divided loyalty in Israel, when Baal worship threatened covenant life. Elijah's departure marked a transition of prophetic responsibility, witnessed by sons of the prophets and sealed by a miraculous ascent.</p>",
        "<p>Elisha refused to leave Elijah as they traveled from Gilgal to the Jordan. Elijah struck the water with his cloak and it divided. As they walked and talked, a fiery chariot separated them and Elijah was taken to heaven in a whirlwind, leaving his mantle to Elisha.</p>",
        ["How do transitions of spiritual leadership affect a community?", "What does Elisha's refusal to leave teach about mentorship?", "Why is Elijah's departure shown as both glorious and sobering?"]),
    entry(319, 12, 5, 14,
        "So he went down and dipped himself in the Jordan seven times, as the man of God had told him, and his flesh was restored and became clean like that of a young boy.",
        "<p>Naaman was commander of Aram's army, a respected outsider with leprosy. Elisha's simple command to wash in the Jordan challenged pride and national prejudice, showing that God's healing often comes through humble obedience to an unimpressive word.</p>",
        "<p>Naaman expected dramatic healing from Elisha and initially scorned washing in Israel's modest river. His servants persuaded him to try. After seven dips in the Jordan, his skin was restored like a young boy's, and he recognized the God of Israel.</p>",
        ["What keeps people from simple obedience to God's instructions?", "How does pride interfere with receiving grace?", "When has counsel from a humble voice changed your direction?"]),
    entry(320, 13, 4, 10,
        "Jabez cried out to the God of Israel, \"Oh, that you would bless me and enlarge my territory! Let your hand be with me, and keep me from harm so that I will be free from pain.\" And God granted his request.",
        "<p>The genealogy of Judah in Chronicles interrupts lineage with Jabez's prayer, suggesting his story was remembered because of bold faith. In post-exilic Israel, Chronicles encouraged hope that earnest prayer before the God of Israel could reshape a family's future.</p>",
        "<p>Amid lists of descendants, Jabez stands out as more honorable than his brothers. His name recalled pain, yet he prayed for blessing, expanded influence, God's hand, and protection from harm. The narrative notes simply that God granted what he asked.</p>",
        ["Is it right to pray boldly for blessing and influence?", "How does God respond to honest prayers rooted in dependence?", "What pain in your past might become a place of faithful petition?"]),
    entry(321, 14, 20, 9,
        "If calamity comes upon us, whether the sword of judgment, or plague or famine, we will stand in your presence before this temple that bears your Name and will cry out to you in our distress, and you will hear us and save us.'",
        "<p>Jehoshaphat led Judah when surrounding nations threatened invasion. Chronicles presents his prayer at the temple as a model of communal dependence: God's people standing before the place bearing his Name and crying out together in crisis.</p>",
        "<p>A vast army marched against Judah. Jehoshaphat proclaimed a fast and led assembly prayer in Jerusalem. He acknowledged God's rule over nations and confessed that in sword, plague, or famine, Judah would stand before God's temple, cry out, and trust him to hear and save.</p>",
        ["How does corporate prayer change a community's response to crisis?", "What does standing before God's Name imply about worship and trust?", "When have you cried out together with others and seen deliverance?"]),
    entry(322, 15, 1, 3,
        "Any of his people among you may go up to Jerusalem in Judah and build the temple of the Lord, the God of Israel, the God who is in Jerusalem, and may their God be with them.",
        "<p>Cyrus of Persia conquered Babylon and allowed exiled peoples to return home. Ezra opens with a royal decree permitting Jews to rebuild the temple, marking the first wave of return under Sheshbazzar and Zerubbabel around the mid-sixth century BC.</p>",
        "<p>After decades in Babylon, Cyrus issued a proclamation that the Lord had appointed him to build a house in Jerusalem. He released vessels taken from the temple and invited any of God's people to go up and rebuild, with prayer that their God would be with them.</p>",
        ["How does political freedom sometimes serve God's redemptive plans?", "What does returning to rebuild worship require after exile?", "Who around you needs encouragement to participate in restoring faith community?"]),
    entry(323, 16, 4, 6,
        "So we rebuilt the wall till all of it reached half its height, for the people worked with all their heart.",
        "<p>Nehemiah returned to Jerusalem under Artaxerxes to rebuild the city's walls after exile. Opposition from Sanballat and others made the task dangerous, yet unified labor with wholehearted effort turned rubble into defense and renewed communal identity.</p>",
        "<p>Nehemiah organized families to repair sections of Jerusalem's broken wall. Despite mockery and threats, workers carried tools in one hand and weapons in the other. Progress came because the people labored together with all their heart until half the wall stood rebuilt.</p>",
        ["What does working with all your heart look like under opposition?", "How can shared mission unite people with different skills?", "What half-finished work in your church or family needs renewed wholehearted effort?"]),
    entry(324, 17, 8, 8,
        "Now write another decree in the king's name in behalf of the Jews as seems best to you, and seal it with the king's signet ring—for no document written in the king's name and sealed with his ring can be revoked.\"",
        "<p>Esther takes place in the Persian court of Xerxes, where Jewish exiles lived under imperial law. Haman's genocidal decree against Jews was legal yet wicked; Mordecai and Esther needed royal authority to issue a counter-decree protecting their people.</p>",
        "<p>After Haman's plot was exposed and he was executed, danger remained because the first edict could not be canceled. The king gave Esther and Mordecai authority to write new decrees sealed with his ring, allowing Jews to defend themselves on the appointed day.</p>",
        ["How does courage in high places protect vulnerable communities?", "What does this story teach about the limits and uses of human law?", "When has timely action prevented harm that seemed already sealed?"]),
    entry(325, 18, 28, 28,
        "And he said to the human race, \"The fear of the Lord—that is wisdom, and to shun evil is understanding.\"",
        "<p>Job explores suffering, wisdom, and God's governance in the ancient world. Chapter 28 uses mining imagery to show that humans can extract treasure from the earth yet cannot buy wisdom. True wisdom begins with reverent fear of the Lord who gives understanding.</p>",
        "<p>Job's poem describes how miners probe deep places for precious metals while wisdom remains hidden from birds and beasts. Riches cannot purchase it. The chapter closes with God's definition: for humanity, wisdom is fearing the Lord and turning away from evil.</p>",
        ["How is godly wisdom different from intelligence or success?", "What does shunning evil teach about the practice of understanding?", "Where do you seek wisdom when circumstances confuse you?"]),
    entry(326, 18, 38, 1,
        "Then the Lord spoke to Job out of the storm. He said:",
        "<p>After chapters of debate among Job and his friends, God answered from a whirlwind. In the ancient Near East, storms symbolized divine power. Rather than explaining every detail of Job's suffering, God revealed his unmatched wisdom and authority over creation.</p>",
        "<p>Job had demanded a hearing before God, maintaining integrity amid loss. Elihu's speeches prepared the way. Then the Lord answered Job out of the storm, opening a lengthy divine discourse that questions Job's capacity to run the cosmos and calls him to humble trust.</p>",
        ["Why might God answer suffering with questions about creation?", "How does encountering God's greatness change our complaints?", "When have you needed to hear God speak in the midst of your storm?"]),
    entry(327, 19, 4, 8,
        "In peace I will lie down and sleep, for you alone, Lord, make me dwell in safety.",
        "<p>Psalm 4 is a Davidic evening prayer amid distress, likely composed when enemies spread falsehood and social pressure threatened peace. Ancient Israel often ended day with trust in God's protection rather than anxiety over opponents or circumstances.</p>",
        "<p>David calls the Lord to relieve and answer him. He warns against sin and urges trust. Many ask who will bring prosperity, but David declares the Lord gives greater joy than abundance. He lies down in peace because God alone makes him dwell in safety.</p>",
        ["What keeps you from sleeping in peace?", "How does trusting God alone differ from trusting favorable circumstances?", "What evening habits could help you end the day with this prayer?"]),
    entry(328, 19, 8, 1,
        "Lord, our Lord, how majestic is your name in all the earth! You have set your glory in the heavens.",
        "<p>Psalm 8 celebrates God's majesty revealed in creation and his surprising care for humanity. In a world where nations boasted of their gods, Israel proclaimed that the Lord's name is glorious across the whole earth and displayed in the heavens above.</p>",
        "<p>The psalm opens and closes with the same refrain about God's majestic name. David marvels at the moon and stars, then ponders why the Lord cares for frail humans crowned with glory and honor and given dominion over creation.</p>",
        ["How does creation declare God's majesty to you?", "Why is it remarkable that the majestic God cares for humans?", "How should dominion over creation be exercised faithfully?"]),
    entry(329, 19, 16, 11,
        "You make known to me the path of life; you will fill me with joy in your presence, with eternal pleasures at your right hand.",
        "<p>Psalm 16 is a trust psalm attributed to David, expressing confidence in God's counsel and inheritance. In Israel's worship, joy in God's presence was not escapism but the fruit of clinging to the Lord as one's highest good and secure refuge.</p>",
        "<p>David declares the Lord is his portion and cup, his pleasant inheritance. He will not follow other gods. Because the Lord shows the path of life, David anticipates fullness of joy in God's presence and pleasures forever at his right hand.</p>",
        ["What does the path of life from God look like in daily decisions?", "How is joy in God's presence different from temporary happiness?", "What other 'gods' compete for your ultimate allegiance?"]),
    entry(330, 19, 18, 2,
        "The Lord is my rock, my fortress and my deliverer; my God is my rock, in whom I take refuge, my shield and the horn of my salvation, my stronghold.",
        "<p>Psalm 18 is David's song of deliverance after the Lord rescued him from Saul and enemies. Military metaphors of rock, fortress, and shield reflected real warfare in ancient Israel, yet David applied them to God's saving power rather than human strength alone.</p>",
        "<p>David opens with passionate praise, calling the Lord his strength and the one worth loving. He stacks images of security—rock, fortress, deliverer, refuge, shield, horn of salvation, stronghold—celebrating God's rescue from overwhelming foes.</p>",
        ["Which image of God as protector speaks most to your current need?", "How does praise after deliverance strengthen future faith?", "What enemies or pressures make you run to God as stronghold?"]),
    entry(331, 19, 25, 4,
        "Show me your ways, Lord, teach me your paths.",
        "<p>Psalm 25 is a prayer of David seeking guidance and forgiveness. In a culture where kings were expected to model covenant faithfulness, this psalm voices humble dependence on God for moral direction rather than self-confident navigation of life's complexities.</p>",
        "<p>David lifts his soul to the Lord, asking not to be shamed and trusting God to teach and lead. He acknowledges sinners and the merciful God who instructs the humble. His central petition is simple: show your ways and teach your paths.</p>",
        ["What situation makes you cry out for God to show his ways?", "How does humility open a person to divine instruction?", "Who can you disciple by walking God's paths together?"]),
    entry(332, 19, 29, 11,
        "The Lord gives strength to his people; the Lord blesses his people with peace.",
        "<p>Psalm 29 portrays the Lord as king over the storm, whose voice thunders across creation. After depicting God's power breaking cedars and shaking wilderness, the psalm closes with blessing for his people, strength and peace granted from the cosmic King.</p>",
        "<p>The psalm calls heavenly beings to ascribe glory to the Lord whose voice rolls like thunder over waters and mountains. Worshipers in the temple cry Glory! The psalm ends with the Lord enthroned over the flood, giving strength and peace to his people.</p>",
        ["How does God's power over creation relate to peace for his people?", "What does strength from the Lord enable you to do today?", "Why does worship often move from awe at power to confidence in peace?"]),
    entry(333, 19, 33, 12,
        "Blessed is the nation whose God is the Lord, the people he chose for his inheritance.",
        "<p>Psalm 33 is a communal hymn praising God's word and sovereign counsel. In the ancient world, nations trusted military might and alliances; Israel was taught that true blessedness came from belonging to the Lord who chose them as his treasured inheritance.</p>",
        "<p>The psalm urges fresh praise with music and shouts, declaring that the Lord's word created the heavens and his plans stand forever. Kings and horses cannot save. Blessed is the nation whose God is the Lord, the people he selected as his own inheritance.</p>",
        ["How should citizens of any nation understand blessedness before God?", "What false sources of security rival trust in the Lord today?", "What does being God's chosen inheritance require in conduct?"]),
    entry(334, 19, 40, 1,
        "I waited patiently for the Lord; he turned to me and heard my cry.",
        "<p>Psalm 40 reflects David's experience of deliverance from a desperate situation, later read by Israel as a model of patient trust. In temple worship, testimonies of waiting and answered prayer strengthened the community's hope in God's attentive mercy.</p>",
        "<p>David testifies that he waited patiently for the Lord, who inclined to him and heard his cry. God lifted him from the pit and set his feet on rock, putting a new song in his mouth. Many will see and fear and put trust in the Lord.</p>",
        ["What does patient waiting for the Lord look like in your situation?", "How can testimony of answered prayer encourage others?", "When has God turned toward you after a season of crying out?"]),
    entry(335, 19, 42, 11,
        "Why, my soul, are you downcast? Why so disturbed within me? Put your hope in God, for I will yet praise him, my Savior and my God.",
        "<p>Psalm 42 expresses deep longing for God's presence, likely during exile from temple worship. Korah's sons voiced what many faithful Israelites felt when enemies mocked and circumstances pressed down the soul, yet hope could be preached to one's own heart.</p>",
        "<p>The psalmist thirsts for God like a deer for water and recalls past worship with tears. Taunted by foes, his soul is downcast. Twice he speaks to himself: why are you disturbed? Put hope in God, for I will yet praise my Savior and my God.</p>",
        ["How do you preach hope to your own soul when discouraged?", "What does praising God 'yet' imply about faith in darkness?", "When has honest lament turned toward confident hope?"]),
    entry(336, 19, 55, 22,
        "Cast your cares on the Lord and he will sustain you; he will never let the righteous be shaken.",
        "<p>Psalm 55 is a lament where David grieves betrayal by a close companion. In a culture where covenant loyalty was sacred, treachery from a friend felt unbearable. The psalm moves from anguish toward trust that God will bear the burden and uphold the righteous.</p>",
        "<p>David cries out evening, morning, and noon, overwhelmed by violence and deceit. He wishes he could flee like a dove. Yet he commands himself to cast cares on the Lord, confident that God will sustain and never allow the righteous to be moved.</p>",
        ["What burdens do you need to cast on the Lord today?", "How does betrayal test faith differently than ordinary hardship?", "What does it mean to be sustained when circumstances still hurt?"]),
    entry(337, 19, 62, 5,
        "Yes, my soul, find rest in God; my hope comes from him.",
        "<p>Psalm 62 is a quiet trust psalm, likely composed when David faced political threats. Surrounded by attackers who seemed stable yet were fragile, David anchored his soul in God alone as rock, salvation, and source of hope rather than in human schemes.</p>",
        "<p>David waits in silence for God alone, warning against trusting in extortion or riches. People of low and high position are fleeting. Twice he tells his soul to wait for God alone. Here he urges his soul to find rest in God because hope comes from him.</p>",
        ["How do you practice soul-level rest in God?", "What substitutes for God compete with your hope?", "Why does David speak to his own soul instead of only to God?"]),
    entry(338, 19, 73, 26,
        "My flesh and my heart may fail, but God is the strength of my heart and my portion forever.",
        "<p>Psalm 73 wrestles with envy of the prosperous wicked until worship in the sanctuary reorients perspective. Asaph's confession became a community lesson: outward success without God is hollow, while nearness to the Lord is ultimate wealth.</p>",
        "<p>Asaph nearly stumbled, envying arrogant evildoers at ease. Entering God's sanctuary clarified their end and his foolish bitterness. He concludes that though flesh and heart fail, God remains the strength of his heart and his portion forever.</p>",
        ["When have you envied people who seemed to prosper without God?", "What does God as your portion mean financially and spiritually?", "How does worship reset distorted perspective?"]),
    entry(339, 19, 84, 11,
        "For the Lord God is a sun and shield; the Lord bestows favor and honor; no good thing does he withhold from those whose walk is blameless.",
        "<p>Psalm 84 expresses longing for God's dwelling, likely by Korah's sons when distance from the temple ached in exile or travel. Pilgrims yearned for courts where God's presence was known, trusting that those who seek him receive light, protection, and generous goodness.</p>",
        "<p>The psalm blesses those who dwell in God's house and whose strength is in him. Even a single day in his courts surpasses a thousand elsewhere. The Lord is sun and shield, giving grace and glory, withholding no good thing from those who walk blamelessly.</p>",
        ["What do you long for when you are distant from gathered worship?", "How is God both sun and shield in your current season?", "What does blameless walking look like as dependence rather than perfection?"]),
    entry(340, 19, 91, 1,
        "Whoever dwells in the shelter of the Most High will rest in the shadow of the Almighty.",
        "<p>Psalm 91 offered assurance to those living under threat in a dangerous world. Ancient Israelites faced disease, warfare, and night terrors. The psalm pictures intimate refuge under God's wings for those who make the Most High their dwelling place.</p>",
        "<p>The psalmist declares safety for the one who rests in the Almighty's shadow, trusting divine protection from traps, plague, and terror by night. Angels are commanded to guard, and God promises to answer those who love him and know his name.</p>",
        ["What does dwelling in God's shelter mean practically?", "How do promises of protection relate to real suffering believers face?", "How can you rest in God's shadow amid anxiety?"]),
    entry(341, 19, 95, 1,
        "Come, let us sing for joy to the Lord; let us shout aloud to the Rock of our salvation.",
        "<p>Psalm 95 is a call to worship used in Israel's liturgy, inviting the community to rejoice before the Lord who made the sea and dry land. It also warns against hardening hearts as in the wilderness, linking celebration with obedient listening.</p>",
        "<p>The psalm opens with corporate invitation to joyful song and loud praise to the Rock of salvation. It calls nations to bow before the Lord our Maker and Shepherd. Later it urges openness to his voice today, unlike rebellious Israel at Meribah.</p>",
        ["What makes joyful shouting appropriate in worship?", "How does remembering creation deepen praise?", "Where might your heart be hardening toward God's voice?"]),
    entry(342, 19, 96, 1,
        "Sing to the Lord a new song; sing to the Lord, all the earth.",
        "<p>Psalm 96 is an enthronement hymn calling all nations to recognize the Lord's glory. Israel's worship was never meant to stay private; the God who judged idols and ruled the world deserved fresh praise from the whole earth and every people.</p>",
        "<p>The psalm summons a new song to the Lord, proclaiming salvation day after day among the nations. It declares God's greatness, splendor, and worthiness of glory. Creation itself should rejoice because the Lord comes to judge the earth with righteousness.</p>",
        ["What might a new song to the Lord sound like in your life now?", "Why should worship include proclamation to the nations?", "How does God's coming judgment relate to joyful singing?"]),
    entry(343, 19, 103, 8,
        "The Lord is compassionate and gracious, slow to anger, abounding in love.",
        "<p>Psalm 103 is David's hymn of personal and communal blessing, echoing God's self-description after Israel's golden calf sin in Exodus 34. In every generation, Israel needed to remember that God's character is merciful before it is punitive.</p>",
        "<p>David calls his soul to bless the Lord and not forget benefits like forgiveness, healing, and redemption. He highlights God's compassion, grace, patience, and steadfast love, assuring that he does not treat us as our sins deserve nor repay according to iniquities.</p>",
        ["Which of God's benefits in Psalm 103 do you most need to remember?", "How does slow anger shape the way you treat others?", "Why must worship begin with blessing the Lord from the soul?"]),
    entry(344, 19, 107, 1,
        "Give thanks to the Lord, for he is good; his love endures forever.",
        "<p>Psalm 107 opens a collection of thanksgiving psalms recounting how God rescued wanderers, prisoners, the sick, and sailors. Its refrain became a communal reminder that Israel's story—and the world's hope—rests on the Lord's enduring loyal love.</p>",
        "<p>The psalm calls the redeemed of the Lord to gather and testify. Four vignettes show people in distress who cried to the Lord and were saved. Each story returns to the refrain: give thanks, for he is good and his love endures forever.</p>",
        ["What rescue story can you tell that ends with thanksgiving?", "Why is God's enduring love central to repeated worship?", "Who needs to hear your testimony of being redeemed?"]),
    entry(345, 19, 111, 1,
        "Praise the Lord. I will extol the Lord with all my heart in the council of the upright and in the assembly.",
        "<p>Psalm 111 is an acrostic wisdom hymn celebrating God's works and precepts. In the assembly of the upright, wholehearted praise was both doxology and instruction, teaching the next generation that holy awe is the beginning of wise living.</p>",
        "<p>The psalmist vows to praise the Lord with all his heart among the congregation. He recounts God's glorious deeds, provision, covenant faithfulness, and trustworthy commands. The fear of the Lord is the beginning of wisdom and understanding.</p>",
        ["What does praising with all your heart look like in community?", "How do God's works and commands belong together in worship?", "How does holy fear lead to wisdom rather than paralysis?"]),
    entry(346, 19, 116, 1,
        "I love the Lord, for he heard my voice; he heard my cry for mercy.",
        "<p>Psalm 116 is a thanksgiving psalm from someone spared from death, possibly after illness or danger. In temple worship, such personal testimony expressed love for God rooted in experienced mercy rather than abstract religious duty.</p>",
        "<p>The psalmist recalls anguish and sorrow when death seemed near. He called on the Lord's name and was delivered. His response is love for the God who heard his voice, followed by vows to walk before the Lord in the land of the living.</p>",
        ["How has answered prayer deepened your love for God?", "What vows of gratitude follow deliverance in your life?", "Why is personal testimony valuable in gathered worship?"]),
    entry(347, 19, 119, 11,
        "I have hidden your word in my heart that I might not sin against you.",
        "<p>Psalm 119 is an extended meditation on Torah as God's life-giving instruction. In a world of competing wisdom, the psalmist treasures Scripture internally, knowing that memorized and loved word shapes desire and guards against sin before it takes root.</p>",
        "<p>Throughout the psalm the writer delights in statutes, seeks God with whole heart, and asks for teaching and understanding. Here he stores God's word in the heart as internal defense, linking meditation with practical holiness and joyful obedience.</p>",
        ["What Scripture have you hidden in your heart recently?", "How does internalized word help in moments of temptation?", "What habits help you treasure God's instruction rather than merely read it?"]),
    entry(348, 19, 130, 5,
        "I wait for the Lord, my whole being waits, and in his word I put my hope.",
        "<p>Psalm 130 is a penitential song of ascents, cried from the depths. Pilgrims approaching Jerusalem knew sin could block fellowship with God, yet they waited with total being for the Lord who forgives and speaks hopeful word to those who fear him.</p>",
        "<p>The psalmist pleads from deep distress, acknowledging that no one could stand if God marked every sin. He waits for the Lord more than watchmen wait for morning. His whole being waits, and hope rests firmly in God's word of forgiveness and redemption.</p>",
        ["What does waiting with your whole being feel like in practice?", "How is hope in God's word different from optimism?", "When have you cried from the depths and still chosen to wait?"]),
    entry(349, 19, 133, 1,
        "How good and pleasant it is when God's people live together in unity!",
        "<p>Psalm 133 is a brief song of ascents celebrating brotherly unity among pilgrims. In a nation often divided by tribe, politics, and sin, harmony among God's people was as refreshing as precious oil and dew on Mount Hermon, blessing life together.</p>",
        "<p>David exclaims that unity among brothers is good and pleasant, comparing it to oil running down Aaron's beard and dew on Hermon descending on Zion. There the Lord bestows blessing, even life forevermore, linking communal harmony with divine favor.</p>",
        ["Where is God calling you to pursue unity rather than division?", "Why is unity among believers compared to sacred anointing?", "What practices help God's people live together in peace?"]),
    entry(350, 19, 139, 23,
        "Search me, God, and know my heart; test me and know my anxious thoughts.",
        "<p>Psalm 139 proclaims God's omniscience and presence from womb to journey's end. After celebrating that God knit the psalmist together and knows every path, David invites divine examination, wanting anxious thoughts exposed and led in the everlasting way.</p>",
        "<p>David marvels that God searches and knows him completely, perceiving thoughts from afar. He flees God's Spirit in vain, for darkness is light to God. He ends with a prayer for God to search his heart, know anxious thoughts, and lead him in the way everlasting.</p>",
        ["Why is it comforting and unsettling that God knows your anxious thoughts?", "What do you fear God might find if he searches your heart?", "How can you invite God's leading in the everlasting way this week?"]),
    entry(351, 19, 143, 8,
        "Let the morning bring me word of your unfailing love, for I have put my trust in you. Show me the way I should go, for to you I entrust my life.",
        "<p>Psalm 143 is a morning prayer from David pursued by enemies, one of the penitential psalms. Ancient believers often began day seeking confirmation of God's steadfast love and guidance, entrusting life direction to the Lord before circumstances could overwhelm.</p>",
        "<p>David pleads for mercy, remembering God's faithfulness and asking not to be judged by foes. His spirit grows faint within him. At dawn he asks for word of unfailing love because he trusts God, and requests clear direction because his life is entrusted to him.</p>",
        ["How could you begin mornings seeking word of God's love?", "What decision needs you to ask God to show the way?", "What does entrusting your life to God involve beyond a phrase?"]),
    entry(352, 19, 150, 6,
        "Let everything that has breath praise the Lord. Praise the Lord.",
        "<p>Psalm 150 closes the Psalter with unrestrained call to praise using every instrument in the sanctuary. Israel's worship book ends not with complaint or question but with universal doxology, inviting all living creatures to magnify the Lord.</p>",
        "<p>The psalm summons praise in God's sanctuary and mighty heavens for his acts and surpassing greatness. Trumpets, harps, lyres, pipes, and cymbals join the chorus. The final verse widens praise to everything that breathes, ending with Hallelujah.</p>",
        ["What instruments or gifts can you use to praise God today?", "Why does Scripture end the Psalms with all-breath praise?", "How can your daily speech join everything that breathes in worship?"]),
    entry(353, 20, 2, 6,
        "For the Lord gives wisdom; from his mouth come knowledge and understanding.",
        "<p>Proverbs presents wisdom literature rooted in Israel's fear of the Lord. In a culture offering many voices about success and morality, Solomon's instruction insists that true knowledge and understanding originate from God's mouth, not merely human experience.</p>",
        "<p>Chapter 2 urges seeking wisdom like silver and searching for it like hidden treasure. Then the Lord gives wisdom, knowledge, and understanding from his mouth, guarding paths of justice and shielding those who walk with integrity.</p>",
        ["How do you pursue wisdom as treasure rather than information?", "What voices compete with God's mouth for your understanding?", "Where do you need divine wisdom for a decision right now?"]),
    entry(354, 20, 10, 12,
        "Hatred stirs up conflict, but love covers over all wrongs.",
        "<p>Proverbs 10 contrasts the way of the righteous and the wicked in short, memorable lines for daily life. In communities bound by kinship and covenant, unchecked hatred escalated quarrels, while love pursued reconciliation rather than exposing every fault.</p>",
        "<p>The chapter offers dozens of vivid comparisons about speech, work, and character. This proverb addresses relational strife directly: hatred provokes ongoing conflict, but love acts to cover offenses, not by ignoring evil but by seeking peace and restoration.</p>",
        ["How is love that covers wrongs different from enabling sin?", "Where is hatred stirring conflict in your relationships?", "What step toward reconciliation can love take this week?"]),
    entry(355, 20, 11, 14,
        "For lack of guidance a nation falls, but victory is won through many advisers.",
        "<p>Proverbs 11 addresses public life as well as personal virtue. Ancient Israel's leaders made decisions affecting justice, defense, and worship. The proverb teaches humility that wise governance listens to many counselors rather than isolated self-confidence.</p>",
        "<p>Surrounding sayings praise integrity, generosity, and prudent speech. Here national stability is tied to guidance: without it peoples fall, yet with an abundance of counselors there is victory, emphasizing collaborative wisdom over rash solitary rule.</p>",
        ["When have you benefited from many advisers instead of deciding alone?", "How can churches and families practice humble counsel?", "What is the difference between many advisers and conflicting noise?"]),
    entry(356, 20, 12, 25,
        "Anxiety weighs down the heart, but a kind word cheers it up.",
        "<p>Proverbs recognizes emotional life as part of wisdom. In a society without modern mental health language, the sage observed how inner heaviness could be lifted by simple gracious speech, showing that words carry real power to burden or refresh the heart.</p>",
        "<p>Chapter 12 contrasts truthful lips with lying, diligent hands with laziness, and fools with the wise. This verse names anxiety's crushing effect on the heart and pairs it with the healing social medicine of timely, kind words spoken to someone weighed down.</p>",
        ["Who needs a kind word from you today?", "How does anxiety show up in your body and decisions?", "What kind words have cheered you when your heart was heavy?"]),
    entry(357, 20, 14, 12,
        "There is a way that appears to be right, but in the end it leads to death.",
        "<p>Proverbs repeatedly warns that appearances deceive. Israel lived among nations with alternate paths to security and meaning. Wisdom literature insists that moral intuition and popular consensus cannot be final guides; outcomes reveal whether a way truly aligns with God's life-giving order.</p>",
        "<p>Chapter 14 contrasts builders of folly and wisdom, truthful witnesses and false scales. This sober proverb reminds readers that a path can feel right yet end in death, calling for humility, counsel, and reverence for the Lord beyond surface confidence.</p>",
        ["What path looks right to you that needs testing against God's word?", "How do outcomes reveal wisdom or folly over time?", "Who helps you see blind spots before the end is clear?"]),
    entry(358, 20, 15, 1,
        "A gentle answer turns away wrath, but a harsh word stirs up anger.",
        "<p>Proverbs 15 applies wisdom to speech in home, market, and court. In honor-shame culture, heated words could ignite lasting feuds. Gentle responses were not weakness but skilled peacemaking that de-escalated conflict and preserved relationships under God.</p>",
        "<p>The chapter praises the tongue that brings healing, prudent lips, and prayer of the upright. This famous proverb contrasts two speech patterns: gentle answers that defuse wrath and harsh words that provoke fresh anger, teaching discipline in moment of tension.</p>",
        ["When did a gentle answer change a conversation's direction?", "What triggers harsh words in you under stress?", "How can you prepare gentle responses before conflict arises?"]),
    entry(359, 20, 17, 17,
        "A friend loves at all times, and a brother is born for a time of adversity.",
        "<p>Proverbs 17 addresses family loyalty and friendship in ordinary Israelite life. True companionship was tested not in prosperity but adversity. The proverb distinguishes constant love of a friend from the crisis-born solidarity of a brother standing with you in trouble.</p>",
        "<p>Surrounding verses warn about quarrels, fools, and corrupt speech. Here wisdom celebrates relationships that endure: a friend who loves in every season and a brother who comes alongside specifically when adversity strikes, embodying covenant faithfulness in human form.</p>",
        ["Who has loved you at all times, and how can you thank them?", "How can you be a brother or sister born for someone else's adversity?", "What is the difference between fair-weather friendship and faithful love?"]),
    entry(360, 20, 18, 10,
        "The name of the Lord is a fortified tower; the righteous run to it and are safe.",
        "<p>In ancient warfare, towers offered refuge when enemies approached. Proverbs uses that image for the Lord's name—the revealed character and promise of God—as secure shelter for the righteous who flee to him rather than to idols, wealth, or human strength.</p>",
        "<p>Chapter 18 warns about isolation, rash speech, and bribery. This verse offers hope: God's name is a strong tower. The righteous run into it and are safe, picturing urgent trust when danger presses and no human defense is enough.</p>",
        ["What danger makes you want to run to the Lord's name?", "How does knowing God's character function as a safe tower?", "What false towers do people run to for safety?"]),
    entry(361, 20, 19, 21,
        "Many are the plans in a person's heart, but it is the Lord's purpose that prevails.",
        "<p>Proverbs 19 balances human agency with divine sovereignty. People in every age draft plans for security, reputation, and legacy, yet Israel's sages taught that ultimate outcomes belong to the Lord, inviting humility before the God who directs history.</p>",
        "<p>The chapter addresses poverty and integrity, parental discipline, and the folly of rage. This proverb acknowledges abundant human planning while asserting that the Lord's purpose stands, a reminder to hold ambitions with open hands before God.</p>",
        ["Which plans in your heart need to be submitted to God's purpose?", "How does God's prevailing purpose bring peace when plans fail?", "When have you seen the Lord redirect your intentions for good?"]),
    entry(362, 20, 21, 1,
        "In the Lord's hand the king's heart is a stream of water that he channels toward all who please him.",
        "<p>Proverbs 21 speaks to subjects living under royal power in Israel and surrounding nations. Political leaders seemed autonomous, yet wisdom confessed that the Lord could direct a king's heart like irrigation channels in a field, turning policy according to divine pleasure.</p>",
        "<p>The chapter commends justice, diligent planning, and generosity while warning against bribery and pride. This verse offers quiet hope: even royal decisions are not beyond God's guidance, as he turns the king's heart wherever he wills.</p>",
        ["How does this proverb shape prayer for leaders?", "Why is it tempting to fear human power more than trust God's direction?", "Who pleases the Lord in ways that affect communities around them?"]),
    entry(363, 20, 23, 7,
        "for they are the kind of people who are always thinking about the cost. \"Eat and drink,\" they say to you, but their heart is not with you.",
        "<p>Proverbs 23 warns against corrupting influences at rich tables and against envying oppressors. Ancient hospitality could mask stinginess or manipulation. Wisdom teaches discernment when generous words do not match inward calculation and selfish intent.</p>",
        "<p>Earlier verses caution about dining with rulers and craving their delicacies. This line exposes a miser whose thoughts constantly calculate expense. He may say eat and drink, yet his heart is far from genuine generosity, warning listeners to read motives not only words.</p>",
        ["How can you discern when hospitality is not sincere?", "Where are you tempted to say one thing while thinking another?", "Why does wisdom attend to the heart behind polite speech?"]),
    entry(364, 20, 28, 13,
        "Whoever conceals their sins does not prosper, but the one who confesses and renounces them finds mercy.",
        "<p>Proverbs 28 addresses rulers, the poor, and the wise in a society where reputation and wealth tempted people to hide wrongdoing. Israel's covenant life assumed that prosperity without integrity was hollow and that mercy followed honest confession before God and community.</p>",
        "<p>The chapter contrasts the bold wicked with the trusting righteous and warns against hard hearts. This proverb promises that concealing sin blocks true flourishing, while confession and turning away from sin open the path to mercy, aligning with broader biblical teaching on repentance.</p>",
        ["What makes concealing sin seem safer than confessing it?", "How does renouncing sin differ from merely admitting it?", "Where do you need to pursue mercy through honest confession?"]),
    entry(365, 20, 29, 18,
        "Where there is no revelation, people cast off restraint; but blessed is the one who heeds wisdom's instruction.",
        "<p>Proverbs 29 closes a major collection with sayings about leadership and social order. The Hebrew term often translated revelation points to visionary prophetic guidance. Without God's disclosed word, communities drift toward unrestrained chaos; blessed are those who keep wise instruction.</p>",
        "<p>Surrounding proverbs address flattery, discipline of children, and anger. This verse links societal restraint to divine revelation and wisdom. When prophetic vision is absent, people throw off limits, but happiness belongs to those who heed the instruction wisdom provides.</p>",
        ["How does God's word provide healthy restraint in society?", "Where do you see casting off restraint when revelation is ignored?", "What wisdom instruction do you need to heed this week?"]),
    entry(366, 20, 30, 5,
        "\"Every word of God is flawless; he is a shield to those who take refuge in him.",
        "<p>Proverbs 30 records the sayings of Agur, who confessed human limitation and lifted up God's sure word. In a world of competing claims and changing opinion, Israel was reminded that divine speech is tested and pure, protecting those who shelter in the Lord.</p>",
        "<p>Agur begins by admitting he lacks understanding of the Holy One. He warns against adding to God's words. Here he declares every word of God flawless, like refined metal, and portrays God as shield for those who take refuge in him rather than in self-sufficiency.</p>",
        ["Why is God's flawless word worth more than human speculation?", "How do people add to God's words today?", "What does taking refuge in God as shield look like under criticism?"]),
    entry(367, 21, 1, 2,
        "\"Meaningless! Meaningless!\" says the Teacher. \"Utterly meaningless! Everything is meaningless.\"",
        "<p>Ecclesiastes comes from the Teacher, traditionally associated with Solomon, reflecting on life under the sun in a prosperous yet perplexing era. After pursuing wisdom, pleasure, and achievement, he confronts readers with the vanity of life apart from God.</p>",
        "<p>The book opens by identifying the Teacher, son of David, king in Jerusalem. He immediately declares vapor-like meaninglessness of everything, a shocking frame for the experiments in wisdom, pleasure, work, and wealth that follow throughout the book.</p>",
        ["Why does Scripture include such blunt pessimism about life under the sun?", "What pursuits have felt meaningless to you?", "How might Ecclesiastes push readers toward God rather than despair?"]),
    entry(368, 21, 4, 12,
        "Though one may be overpowered, two can defend themselves. A cord of three strands is not quickly broken.",
        "<p>Ecclesiastes 4 observes oppression, envy, and loneliness in society. The Teacher affirms companionship and mutual support in labor and hardship, using vivid images of partnership that later readers have often applied to friendship, marriage, and community strength.</p>",
        "<p>After describing oppression and the misery of isolated toil, the Teacher praises two sharing reward and helping each other when one falls. A three-strand cord not quickly broken extends the picture of strengthened unity beyond solitary striving.</p>",
        ["Who partners with you when you are vulnerable to being overpowered?", "How does shared labor change the burden of work?", "What might the three-strand cord mean in your closest relationships?"]),
    entry(369, 21, 7, 8,
        "The end of a matter is better than its beginning, and patience is better than pride.",
        "<p>Ecclesiastes 7 explores wisdom's limits and the mixed reality of life. The Teacher urges sober reflection over quick celebration, teaching that how a matter finishes often reveals more than its promising start, and patient humility outlasts proud impulsiveness.</p>",
        "<p>The chapter advises that sorrow can sharpen the heart and that the day of death may teach more than birth. Amid paradoxes about wisdom and folly, the Teacher values endurance: a matter's end surpasses its beginning, and patience excels pride.</p>",
        ["What unfinished matter requires patience rather than pride?", "How can you evaluate a situation by its end, not only its start?", "When has pride rushed you where patience would have helped?"]),
    entry(370, 21, 11, 5,
        "As you do not know the path of the wind, or how the body is formed in a mother's womb, so you cannot understand the work of God, the Maker of all things.",
        "<p>Ecclesiastes 11 encourages active life under uncertainty. In an age without meteorology or embryology as we know them, wind and womb illustrated mysteries beyond human control. The Teacher uses them to humble readers before God's unfathomable work as Maker of all.</p>",
        "<p>After urging generosity and diversified labor while young, the Teacher reminds readers that clouds and rain follow patterns humans cannot fully grasp. Likewise, the spirit in the womb and God's comprehensive work remain beyond understanding, calling for trust and obedience without total explanation.</p>",
        ["What mysteries of God's work are you trying to control or explain?", "How does humility before the Maker affect daily decisions?", "Where should you act faithfully even when you cannot understand outcomes?"]),
    entry(371, 22, 2, 4,
        "Let him lead me to the banquet hall, and let his banner over me be love.",
        "<p>The Song of Solomon celebrates covenant love in poetic dialogue, often read as marital love and later as allegory of God's love for his people. Ancient wedding imagery of banquet and banner conveyed public delight, protection, and joyful belonging between lovers.</p>",
        "<p>Chapter 2 unfolds spring imagery and the beloved's invitation. The woman desires her lover's leading into the banquet house where his banner over her is love, a picture of honored intimacy, celebration, and unmistakable commitment displayed before others.</p>",
        ["How does love that publicly honors differ from hidden affection?", "What does it mean for God's love to be a banner over his people?", "Where do you experience joyful belonging in covenant relationship?"]),
    entry(372, 22, 3, 1,
        "All night long on my bed I looked for the one my heart loves; I looked for him but did not find him.",
        "<p>Song of Solomon 3 portrays longing and search within love's story. Nighttime seeking expresses deep desire when the beloved seems absent. Jewish and Christian interpreters have heard both human devotion and spiritual yearning for God's presence in this restless search.</p>",
        "<p>On her bed by night the woman seeks the one her heart loves but cannot find him. She resolves to rise and go through city streets and squares, asking watchmen if they have seen him, until she finds the one her soul desires.</p>",
        ["When have you longed for God's presence and felt distance?", "How does honest longing differ from abandoning faith?", "Who helps you seek when you cannot find the beloved on your own?"]),
    entry(373, 23, 1, 18,
        "\"Come now, let us settle the matter,\" says the Lord. \"Though your sins are like scarlet, they shall be as white as snow; though they are red as crimson, they shall be like wool.",
        "<p>Isaiah prophesied in Judah during the eighth century BC, when ritual worship masked injustice and impending Assyrian threat loomed. God invited rebellious Israel to reason together, offering radical forgiveness and transformation beyond what sacrifice alone could achieve.</p>",
        "<p>Isaiah 1 opens with charges against a sinful nation whose worship God rejects because of bloodshed and oppression. After calling for justice, the Lord offers mercy: though sins are scarlet or crimson, they can become white as snow or wool through his cleansing.</p>",
        ["What does it mean to reason together with the Lord about sin?", "How is God's cleansing deeper than religious performance?", "Where do you need hope that scarlet sin can become white?"]),
    entry(374, 23, 12, 2,
        "Surely God is my salvation; I will trust and not be afraid. The Lord, the Lord himself, is my strength and my defense; he has become my salvation.\"",
        "<p>Isaiah 12 is a short song of thanksgiving following promises of restoration. Judah would face exile and return, yet this hymn trains God's people to draw water joyfully from salvation's wells and to make known his deeds among the nations.</p>",
        "<p>The chapter celebrates anger turned away and comfort received. The speaker declares God is salvation, chooses trust over fear, and names the Lord as strength and defense who has become salvation, echoing themes from the exodus and future hope.</p>",
        ["What fear diminishes when you declare God is your salvation?", "How can you draw joyfully from wells of salvation this week?", "Who needs to hear you make known God's deeds?"]),
    entry(375, 23, 25, 8,
        "he will swallow up death forever. The Sovereign Lord will wipe away the tears from all faces; he will remove his people's disgrace from all the earth. The Lord has spoken.",
        "<p>Isaiah 25 is a praise psalm within prophetic literature, celebrating God's victory over enemies and death. For exiled and shamed Israel, the promise that the Lord would end death's power and wipe tears offered hope beyond present humiliation.</p>",
        "<p>On a mountain the Lord prepares feast and destroys the shroud over nations. He swallows up death forever, wipes tears from every face, and removes disgrace from his people throughout the earth. The declaration closes with the Lord has spoken, sealing certainty.</p>",
        ["How does promise of death swallowed shape Christian hope?", "Whose tears do you long to see God wipe away?", "What disgrace has God removed from his people through his word?"]),
    entry(376, 23, 30, 15,
        "This is what the Sovereign Lord, the Holy One of Israel, says: \"In repentance and rest is your salvation, in quietness and trust is your strength, but you would have none of it.",
        "<p>Isaiah 30 addresses Judah's plan to ally with Egypt instead of trusting God against Assyria. Political panic drove them toward horses and chariots. God offered a different strategy: repentance, rest, quiet trust—salvation and strength rejected by restless self-reliance.</p>",
        "<p>Though prophets warned, Judah preferred smooth messages and foreign help. God called returning to him in repentance and finding salvation in rest rather than flight. Strength would come through quiet trust, yet the people refused what their crisis required.</p>",
        ["Where are you seeking strength through hustle instead of trust?", "What does salvation in repentance and rest look like practically?", "Why is quietness difficult when threats feel urgent?"]),
    entry(377, 23, 35, 4,
        "say to those with fearful hearts, \"Be strong, do not fear; your God will come, he will come with vengeance; with divine retribution he will come to save you.\"",
        "<p>Isaiah 35 paints a highway of holiness through the wilderness for ransomed Israel. Exiles with fearful hearts needed assurance that God would come to save, transforming dry land into flourishing and enabling the lame and mute to leap and shout for joy.</p>",
        "<p>The chapter promises gladness and glory on the desert way when God comes. Messengers are told to strengthen those whose hearts tremble: be strong, do not fear, for God will come with vengeance and saving retribution on behalf of his people.</p>",
        ["Who around you needs a message to be strong and not fear?", "How does God's coming to save relate to his justice?", "What wilderness in your life could become a highway of joy?"]),
    entry(378, 23, 38, 17,
        "Surely it was for my benefit that I suffered such anguish. In your love you kept me from the pit of destruction; you have put all my sins behind your back.",
        "<p>Isaiah 38 records Hezekiah's illness and prayer when Assyrian threat still loomed over Judah. The king's psalm of recovery interprets suffering through mercy: anguish led to life, and God in love forgave sin, turning the king's face toward grateful praise.</p>",
        "<p>Hezekiah was sick unto death, prayed, and received fifteen more years. He wrote of bitter soul-chastening, yet concluded his suffering brought benefit because God's love rescued him from the pit and cast his sins behind his back, restoring peace.</p>",
        ["How can suffering become benefit under God's hand?", "What does it mean that God puts sin behind his back?", "When has anguish led you to deeper gratitude for life?"]),
    entry(379, 23, 49, 6,
        "he says: \"It is too small a thing for you to be my servant to restore the tribes of Jacob and bring back those of Israel I have kept. I will also make you a light for the Gentiles, that my salvation may reach to the ends of the earth.\"",
        "<p>Isaiah's Servant Songs address Israel's mission after exile. God's servant—often identified with the nation and later with the Messiah—was appointed not only to regather Jacob but to bring God's salvation to Gentiles, expanding covenant hope to the whole world.</p>",
        "<p>Isaiah 49 opens with the servant's call from the womb and apparent failure. Yet God honors the servant and declares restoring Israel is too small a task; the servant will also be light for nations so salvation reaches earth's ends.</p>",
        ["How does God's mission include outsiders beyond your immediate community?", "Why might restoring Israel seem too small for God's servant?", "How are you called to reflect light to the nations?"]),
    entry(380, 23, 53, 6,
        "We all, like sheep, have gone astray, each of us has turned to our own way; and the Lord has laid on him the iniquity of us all.",
        "<p>Isaiah 53 is the climactic Suffering Servant passage, written centuries before Christ yet describing substitutionary bearing of sin. Judah needed an explanation for exile and a hope for forgiveness that animal sacrifice alone could not fully embody.</p>",
        "<p>The servant is despised, pierced for transgressions, and crushed for iniquities. Peace comes through his wounds. All humanity is pictured as straying sheep, each turning its own way, while the Lord places everyone's iniquity on the servant who suffers on their behalf.</p>",
        ["How does admitting we are straying sheep change self-righteousness?", "What does it mean that the Lord laid iniquity on the servant?", "How should this verse shape gratitude and mission?"]),
    entry(381, 23, 57, 15,
        "For this is what the high and exalted One says— he who lives forever, whose name is holy: \"I live in a high and holy place, but also with the one who is contrite and lowly in spirit, to revive the spirit of the lowly and to revive the heart of the contrite.",
        "<p>Isaiah 57 confronts idolatry and false security while promising mercy to the humble. The God who inhabits eternity and holiness does not remain distant; he draws near to contrite hearts, reviving those crushed by sin and circumstance rather than rewarding the self-sufficient.</p>",
        "<p>God rebukes leaders who stray and people who trust wealth. He declares he dwells high and holy, yet also with the contrite and lowly in spirit, to revive their hearts. Peace belongs to the humble, but the wicked find no rest.</p>",
        ["How does God's nearness to the lowly encourage you?", "What is the difference between contrite humility and self-pity?", "Where do you need God to revive your spirit today?"]),
    entry(382, 23, 58, 11,
        "The Lord will guide you always; he will satisfy your needs in a sun-scorched land and will strengthen your frame. You will be like a well-watered garden, like a spring whose waters never fail.",
        "<p>Isaiah 58 redefines true fasting as justice, generosity, and Sabbath delight rather than performative hunger. God promises guiding presence and abundant provision to those who loose chains of injustice and pour themselves out for the hungry.</p>",
        "<p>After exposing hollow fasting while exploiting workers, the Lord describes repentance that shares bread and clothes the naked. Then light breaks forth, healing appears, and God guides always, satisfies need in drought, strengthens bodies, and makes life like an unfailing spring.</p>",
        ["How does caring for the hungry connect to spiritual vitality?", "What sun-scorched place needs God's guiding satisfaction?", "How can your life become a well-watered garden for others?"]),
    entry(383, 23, 60, 1,
        "\"Arise, shine, for your light has come, and the glory of the Lord rises upon you.",
        "<p>Isaiah 60 envisions restored Zion after exile, radiating God's glory to nations. Darkness covered the earth, but upon Israel God's splendor would dawn, drawing kings and peoples to the light of his presence manifested in the life of his people.</p>",
        "<p>The chapter commands Jerusalem to arise and shine because her light has come and the Lord's glory rises over her. Though darkness covers peoples, the Lord's glory appears over Zion, attracting nations and wealth to the brightness of God's transforming presence.</p>",
        ["What does arising and shining mean for God's people today?", "How does God's glory on his community attract outsiders?", "Where is darkness around you that needs reflected light?"]),
    entry(384, 23, 62, 11,
        "The Lord has made proclamation to the ends of the earth: \"Say to Daughter Zion, 'See, your Savior comes! See, his reward is with him, and his recompense accompanies him.'\"",
        "<p>Isaiah 62 promises Zion a new name and vindication after shame. Watchmen on Jerusalem's walls refuse silence until God establishes the city. The chapter climaxes with global proclamation that salvation approaches with reward and recompense for the redeemed.</p>",
        "<p>God swears never to rest until Zion's righteousness shines like a blazing torch. Nations will see her glory under a new name. The Lord proclaims to earth's ends: tell Daughter Zion her Savior comes with reward and recompense accompanying him.</p>",
        ["How does proclaiming the Savior's coming shape hope in hard seasons?", "What reward and recompense might God bring with salvation?", "Who needs to hear say to Zion your Savior comes?"]),
    entry(385, 23, 64, 4,
        "Since ancient times no one has heard, no ear has perceived, no eye has seen any God besides you, who acts on behalf of those who wait for him.",
        "<p>Isaiah 64 is a corporate lament pleading for God to rend the heavens and come down. Exiled Israel confessed sin yet appealed to God's unique character as the God who works wonders for those who wait, hope, and long for his intervention.</p>",
        "<p>The prayer recalls God's awesome deeds and admits all have become unclean. Then the congregation marvels that no god has been heard or seen acting for those who wait as the Lord does, anchoring hope in his unmatched willingness to help those who hope in him.</p>",
        ["What are you asking God to do that only he can do?", "How does waiting for God differ from passive inaction?", "When have you seen God act on behalf of those who hope?"]),
    entry(386, 23, 66, 1,
        "This is what the Lord says: \"Heaven is my throne, and the earth is my footstool. Where is the house you will build for me? Where will my resting place be?",
        "<p>Isaiah 66 closes the book with tension between temple ritual and humble worship. Post-exilic Judah focused on rebuilding the temple, yet God reminded them that cosmos itself is his dwelling; he looks to the contrite spirit, not merely to impressive structures.</p>",
        "<p>After promises of new heavens and earth, the Lord declares heaven his throne and earth his footstool, questioning what house humans could build and where he would rest. True worship aligns with trembling at his word rather than boasting in construction alone.</p>",
        ["How can worship honor God without reducing him to a building?", "What humble spirit does God value more than impressive religion?", "Where might you be trusting structures over trembling at God's word?"]),
    entry(387, 24, 3, 15,
        "Then I will give you shepherds after my own heart, who will lead you with knowledge and understanding.",
        "<p>Jeremiah prophesied as Judah collapsed toward Babylonian exile. False leaders had scattered the flock through neglect and self-interest. God promised future shepherds after his own heart who would guide Israel with knowledge and understanding, pointing to renewed leadership under covenant faithfulness.</p>",
        "<p>Jeremiah 3 calls Israel and Judah to return despite spiritual adultery. The Lord invites backsliding children and promises to give shepherds matching his heart, who lead with insight rather than exploitation, restoring flock through faithful pastoral care.</p>",
        ["What qualities mark a shepherd after God's own heart?", "How have poor leaders scattered people you care about?", "How can you pray for and support faithful spiritual leadership?"]),
    entry(388, 24, 9, 23,
        "This is what the Lord says: \"Let not the wise boast in their wisdom or the strong boast in their strength or the rich boast in their riches,",
        "<p>Jeremiah 9 laments Judah's mourning over deceit and unfaithfulness. In a society impressed by wisdom, might, and wealth, God redirects boasting toward knowing and understanding the Lord who exercises kindness, justice, and righteousness on earth.</p>",
        "<p>Jeremiah wishes his head a fountain of tears for the slain daughter of his people. He warns against trusting humans and forbids boasting in wisdom, strength, or riches. The only proper boast is understanding and knowing the Lord who delights in covenant loyalty.</p>",
        ["What do you tend to boast in instead of knowing God?", "How does knowing the Lord reshape views of wisdom and wealth?", "What does boasting in kindness and justice look like daily?"]),
    entry(389, 24, 10, 6,
        "No one is like you, Lord; you are great, and your name is mighty in power.",
        "<p>Jeremiah 10 contrasts the living God with worthless idols crafted by human hands. Exiled Judah faced cultures saturated with image worship. Jeremiah's hymn insists that the Lord alone is without compare, great in power and worthy of reverent fear from nations.</p>",
        "<p>The chapter mocks idols that cannot speak or move and must be carried. Families decorate them in vain. Jeremiah exalts the King of nations: none is like the Lord, great and mighty in name, the true God who made earth by power and wisdom.</p>",
        ["How do modern idols resemble Jeremiah's carved images?", "Why is God's unmatched greatness reason for reverent fear?", "How does creation theology support exclusive worship of the Lord?"]),
    entry(390, 24, 15, 16,
        "When your words came, I ate them; they were my joy and my heart's delight, for I bear your name, Lord God Almighty.",
        "<p>Jeremiah's ministry brought loneliness, ridicule, and threat because he spoke God's unpopular word to Judah. Yet he confessed that receiving divine speech was spiritual nourishment and delight, even when that same word made him a target of contempt.</p>",
        "<p>Jeremiah laments being enticed by God and overcome by his word. He did not sit with revelers but sat alone under God's hand. Here he describes eating God's words as joy and heart's delight because he bears the name of the Lord Almighty.</p>",
        ["What does eating God's word mean in your study and obedience?", "How can Scripture bring joy even when obedience is costly?", "What does bearing God's name require in your conduct?"]),
    entry(391, 24, 23, 6,
        "In his days Judah will be saved and Israel will live in safety. This is the name by which he will be called: The Lord Our Righteous Savior.",
        "<p>Jeremiah 23 condemns shepherds who scatter the flock and promises a righteous Branch from David's line. Amid failed kings and coming exile, God pledged a future ruler whose reign would bring salvation and safety, known by the name The Lord Our Righteous Savior.</p>",
        "<p>God denounces false prophets and negligent leaders, then announces he will raise a righteous Branch for David. In his days Judah will be saved and Israel dwell securely. He will be called The Lord Our Righteous Savior, uniting kingship and divine righteousness for his people.</p>",
        ["How does this promise point to hope beyond failed human leaders?", "What does righteousness from God mean compared with self-made virtue?", "How does safety in God's reign shape your political anxieties?"]),
]


def main():
    OUT.parent.mkdir(parents=True, exist_ok=True)
    OUT.write_text(json.dumps(LESSONS, indent=2, ensure_ascii=False) + "\n")
    print(f"Wrote {len(LESSONS)} lessons to {OUT}")


if __name__ == "__main__":
    main()
